-- Create the festivals table
CREATE TABLE IF NOT EXISTS public.festivals (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name TEXT NOT NULL,
    country TEXT NOT NULL,
    region TEXT,
    city TEXT NOT NULL,
    description TEXT,
    dates_approx TEXT,
    rating INTEGER,
    unique_reason TEXT,
    lat FLOAT8 NOT NULL,
    lon FLOAT8 NOT NULL,
    start_month INTEGER, -- 1 to 12
    start_day INTEGER,   -- 1 to 31
    end_month INTEGER,   -- 1 to 12
    end_day INTEGER,     -- 1 to 31
    created_at TIMESTAMPTZ DEFAULT now()
);

-- Enable RLS
ALTER TABLE public.festivals ENABLE ROW LEVEL SECURITY;

-- Create policy to allow public read access
CREATE POLICY "Allow public read access for festivals" ON public.festivals
    FOR SELECT TO public USING (true);

